export function processScenario(scenario: Scenario): unknown {
  const items = scenario.steps[0].items;

  const typeCounts: Record<string, number> = {};
  for (const item of items) {
    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
  }

  let basePremium = 0;
  for (const [type, count] of Object.entries(typeCounts)) {
    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
      basePremium += BLOCK_PREMIUM;
    } else {
      basePremium += count * BASE_PREMIUM[type];
    }
  }
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);

  return [{ premium }];
}

